   158→// ── Main ──────────────────────────────────────────────────────────
   159→export default function Home() {
   160→  const [messages, setMessages] = useState<Msg[]>([]);
   161→  const [animatingIdx, setAnimatingIdx] = useState<number>(-1);
   162→  const [input, setInput] = useState("");
   163→  const [error, setError] = useState<string | null>(null);
   164→  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
