/* ── Root ───────────────────────────────────────────────────────── */
.root {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  z-index: 1;
}

/* ── Landing ────────────────────────────────────────────────────── */
.landing {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  padding-top: 15vh;
  gap: 0;
  padding-bottom: 80px;
  position: relative;
  overflow-y: auto;
  overflow-x: hidden;
}

.vignettePulse {
  position: fixed;
  inset: 0;
  pointer-events: none;
  background: radial-gradient(circle at center, rgba(139, 92, 246, 0.08) 0%, transparent 65%);
  animation: vignette-breathe 6s ease-in-out infinite;
  pointer-events: none;
  z-index: 0;
}

@keyframes vignette-breathe {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 1; }
}

.heroSection {
  display: flex;
  flex-direction: column;
  align-items: center;
  position: relative;
  z-index: 1;
  margin-bottom: var(--space-6);
}

.landingOmega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(96px, 22vw, 180px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  user-select: none;
  animation: omega-breathe 4s ease-in-out infinite;
  transition: all 0.6s var(--ease-snappy);
  letter-spacing: -0.02em;
  will-change: filter, transform;
}

.landingOmega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.landingOmega.responding {
  animation: omega-respond 1.5s ease-out forwards;
}

.taglineStack {
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-top: var(--space-4);
  text-align: center;
}

.tagline1 {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(16px, 3.5vw, 22px);
  font-weight: 700;
  color: var(--gold);
  letter-spacing: 0.3em;
  text-transform: uppercase;
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 0.2s;
  margin-bottom: var(--space-2);
}

.tagline2 {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: clamp(14px, 3vw, 16px);
  color: var(--dim);
  letter-spacing: 0.2em;
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 0.4s;
  margin-bottom: var(--space-1);
}

.tagline3 {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: clamp(11px, 2.5vw, 13px);
  color: var(--dimmer);
  font-style: italic;
  letter-spacing: 0.05em;
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 0.6s;
}

.featureStrip {
  display: flex;
  flex-direction: row;
  gap: var(--space-4);
  margin-bottom: var(--space-6);
  z-index: 1;
  width: 100%;
  max-width: 900px;
  padding: 0 var(--space-4);
  justify-content: center;
}

.featureCard {
  background: var(--glass-bg);
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  padding: var(--space-4) var(--space-3);
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
